-- Note: source contains a duplicate Day 2 block after Day 14; ignored during conversion.

BEGIN;

INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 1,
  'Reset the Body Clock', 'Day 1 - Reset the Body Clock', '', 18,
  '[{"type": "intro", "dayNumber": 1, "dayTitle": "Reset the Body Clock", "goal": "Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight''s sleep may not be perfect yet, but the body has already begun the reset process.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight''s sleep may not be perfect yet, but the body has already begun the reset process."], "highlight": "Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight''s sleep may not be perfect yet, but the body has already begun the reset process."}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian clock, which tells your body when to release melatonin at night. Without this signal, the brain stays confused about when to sleep.", "proTip": "If sunlight is weak, increase exposure to 20-30 minutes."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones, which are one of the biggest causes of insomnia."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Movement early in the day helps build sleep pressure, which makes you naturally tired at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Today follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine stays in the body 6-8 hours, often silently disturbing sleep."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Let the body relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 1 that supports reset the body clock.", "audioStoragePath": "audio/sleep/1.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops, which triggers natural sleepiness. This trick is commonly used in sleep clinics."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a canoe on a calm lake.", "The sky above you is clear and peaceful.", "The water is still and quiet.", "Focus on the scene while breathing slowly.", "If thoughts appear, gently return to the calm image."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Heavy Eyes\" Method", "duration": "1-2 min", "steps": ["When your eyes are closed in bed:", "Keep your eyes closed.", "Look slightly upward behind your eyelids.", "Let your eyes become heavy."], "completionMessage": "This mimics the natural eye position that occurs right before sleep, helping the brain enter sleep mode faster."}, {"type": "close", "message": "Day 1 is complete.", "secondaryMessage": "Start resetting the body clock and nervous system so the brain begins recognizing the signals for sleep. Tonight''s sleep may not be perfect yet, but the body has already begun the reset process."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
  day_title = EXCLUDED.day_title,
  estimated_minutes = EXCLUDED.estimated_minutes,
  updated_at = NOW();

INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 2,
  'Reducing Mental Stimulation', 'Day 2 - Reducing Mental Stimulation', '', 18,
  '[{"type": "intro", "dayNumber": 2, "dayTitle": "Reducing Mental Stimulation", "goal": "Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine.", "By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep."], "highlight": "By repeating the same steps from Day 1 and adding this new technique, the brain slowly begins to associate the routine with sleep."}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian clock, helping the body release melatonin naturally at night. Without this signal, the brain stays confused about when to sleep.", "proTip": "If sunlight is weak, increase exposure to 20-30 minutes."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones and relaxes the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Movement early in the day builds sleep pressure, which helps the body feel naturally tired at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Today follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain in the body 6-8 hours, which can silently disturb sleep."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the voice instructions.", "Let your body relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 2 that supports reducing mental stimulation.", "audioStoragePath": "audio/sleep/2.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops, which naturally triggers sleepiness. This change signals the brain that nighttime has arrived."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying on a quiet beach at sunset.", "You can hear gentle waves and feel a cool breeze.", "Keep breathing slowly while focusing on the scene.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The Cognitive Shuffle", "duration": "1 min", "steps": ["If your mind keeps thinking when trying to sleep, use this technique.", "In your mind, start naming random neutral objects.", "## Example:", "apple", "bridge", "candle", "mountain", "book", "river", "cloud", "Each object should be unrelated to the previous one.", "Continue for 30-60 seconds."], "completionMessage": "This technique distracts the brain from problem-solving mode, which keeps people awake. The mind becomes bored and begins transitioning into sleep mode."}, {"type": "close", "message": "Day 2 is complete.", "secondaryMessage": "Reduce mental stimulation and racing thoughts at night while strengthening the sleep routine."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
