INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 3,
  'Stabilizing Night Sleep', 'Day 3 - Stabilizing Night Sleep', '', 18,
  '[{"type": "intro", "dayNumber": 3, "dayTitle": "Stabilizing Night Sleep", "goal": "Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally.", "By Day 3, many people begin noticing: falling asleep faster, less racing thoughts, and deeper relaxation before sleep"], "highlight": "By Day 3, many people begin noticing: falling asleep faster, less racing thoughts, and deeper relaxation before sleep"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping the body release melatonin naturally at night. Without this signal, sleep timing becomes irregular.", "proTip": "Try to walk slowly while getting sunlight. Movement strengthens the signal to your body clock."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and helps your body shift into a calm state."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Morning movement increases sleep pressure, which helps you feel naturally sleepy later at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain in the body 6-8 hours and delay sleep onset."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 3 that supports stabilizing night sleep.", "audioStoragePath": "audio/sleep/3.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly. This drop triggers the brain to start producing melatonin, making you feel sleepy."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet forest under a clear night sky.", "The air is cool and peaceful.", "Everything around you is still.", "Focus on this scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The Reverse Blinking Technique", "duration": "1-2 min", "steps": ["This trick helps people who try too hard to fall asleep.", "When lying in bed:", "Close your eyes.", "Open them gently for 1-2 seconds.", "Close them again.", "Repeat this 5-10 times slowly."], "completionMessage": "Trying to sleep often creates performance pressure, which keeps the brain alert. Reverse blinking removes that pressure and relaxes the brain, making sleep happen naturally."}, {"type": "close", "message": "Day 3 is complete.", "secondaryMessage": "Reduce the effort and pressure around sleep, allowing the body to fall asleep more naturally."}]'::jsonb
)
ON CONFLICT (program_slug, day_number) DO UPDATE SET
  cards = EXCLUDED.cards,
