INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 4,
  'Reducing Night Awakenings', 'Day 4 - Reducing Night Awakenings', '', 18,
  '[{"type": "intro", "dayNumber": 4, "dayTitle": "Reducing Night Awakenings", "goal": "Improve sleep continuity and reduce middle-of-the-night awakenings.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Improve sleep continuity and reduce middle-of-the-night awakenings.", "By Day 4 many people begin noticing: fewer night wake-ups, faster return to sleep, and deeper relaxation before bed"], "highlight": "By Day 4 many people begin noticing: fewer night wake-ups, faster return to sleep, and deeper relaxation before bed"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping your body release melatonin at night and improve sleep timing.", "proTip": "Try to expose your eyes to full outdoor daylight, not through a window, because glass blocks part of the light signal that helps regulate your body clock."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Movement early in the day increases sleep pressure, which helps you sleep more deeply at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, disturbing sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 4 that supports reducing night awakenings.", "audioStoragePath": "audio/sleep/4.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body experiences a natural drop in temperature, which signals the brain that it is time to sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet field under a clear starry sky.", "The night air is calm and peaceful.", "Everything around you feels safe and quiet.", "Focus on the scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"15-Minute Reset Rule\"", "duration": "5-10 min", "steps": ["If you wake up during the night and cannot fall asleep within about 15 minutes, do this:", "Get out of bed quietly.", "Go to a dimly lit room.", "Sit or read something calm (no phone or bright screens).", "Stay there for 5-10 minutes.", "Return to bed when you feel sleepy."], "completionMessage": "Staying awake in bed can train the brain to associate the bed with frustration and wakefulness. This reset teaches the brain that the bed is only for sleep."}, {"type": "close", "message": "Day 4 is complete.", "secondaryMessage": "Improve sleep continuity and reduce middle-of-the-night awakenings."}]'::jsonb
)
