INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 5,
  'Improving Deep Sleep Quality', 'Day 5 - Improving Deep Sleep Quality', '', 18,
  '[{"type": "intro", "dayNumber": 5, "dayTitle": "Improving Deep Sleep Quality", "goal": "Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles.", "By Day 5 some people begin noticing: falling asleep faster, deeper sleep, and feeling more refreshed in the morning"], "highlight": "By Day 5 some people begin noticing: falling asleep faster, deeper sleep, and feeling more refreshed in the morning"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping the body release melatonin naturally at night.", "proTip": "Combine sunlight exposure with a short walk to strengthen the signal to your body clock."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This helps lower stress hormones and relax the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Morning movement increases sleep pressure, which helps your body fall asleep naturally at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, affecting deep sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 5 that supports improving deep sleep quality.", "audioStoragePath": "audio/sleep/5.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly. This temperature drop signals the brain to prepare for sleep and melatonin release."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet cabin during gentle rain.", "You can hear the soft sound of rain on the roof.", "Everything around you feels calm and safe.", "Focus on the sound and scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Feet Warmth Trick\"", "duration": "1 min", "steps": ["Cold feet can actually make it harder for the body to fall asleep.", "Before going to bed:", "wear light socks", "or", "place a warm blanket over your feet"], "completionMessage": "Warming the feet helps blood vessels expand, which allows heat to leave the body. This helps the body lower its core temperature, which naturally triggers sleep. Many sleep studies show people fall asleep faster when their feet are warm."}, {"type": "close", "message": "Day 5 is complete.", "secondaryMessage": "Improve deep sleep quality and physical relaxation so the body can enter deeper restorative sleep cycles."}]'::jsonb
)
