INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 6,
  'Quieting the Racing Mind', 'Day 6 - Quieting the Racing Mind', '', 18,
  '[{"type": "intro", "dayNumber": 6, "dayTitle": "Quieting the Racing Mind", "goal": "Reduce mental overload before bedtime, allowing the brain to relax and transition into sleep more easily.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Reduce mental overload before bedtime, allowing the brain to relax and transition into sleep more easily.", "By Day 6 many people begin noticing: quieter thoughts at night, less stress before sleep, and falling asleep with less effort"], "highlight": "By Day 6 many people begin noticing: quieter thoughts at night, less stress before sleep, and falling asleep with less effort"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s internal clock, helping your body release melatonin naturally at night.", "proTip": "Try walking slowly while getting sunlight to strengthen your circadian rhythm signal."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Movement early in the day increases sleep pressure, helping the body feel naturally tired at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can stay in the body 6-8 hours, delaying sleep onset."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 6 that supports quieting the racing mind.", "audioStoragePath": "audio/sleep/6.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature naturally drops, which signals the brain to prepare for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet mountain valley at night.", "The air is cool and peaceful.", "Everything around you is still and calm.", "Focus on the scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "journal", "prompt": "Write down everything on your mind: tasks for tomorrow, worries, and any loose thoughts still circling.", "helperText": "About 30 minutes before bed, use a notebook and do not organize it. Just empty your mind onto paper.", "followUpPrompt": "What can you leave on the page so your brain does not keep carrying it tonight?"}, {"type": "close", "message": "Day 6 is complete.", "secondaryMessage": "Reduce mental overload before bedtime, allowing the brain to relax and transition into sleep more easily."}]'::jsonb
)
