INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 7,
  'Strengthening Natural Melatonin', 'Day 7 - Strengthening Natural Melatonin', '', 18,
  '[{"type": "intro", "dayNumber": 7, "dayTitle": "Strengthening Natural Melatonin", "goal": "Support the body''s natural melatonin cycle and strengthen the sleep routine developed during the first week.", "estimatedMinutes": 18}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Support the body''s natural melatonin cycle and strengthen the sleep routine developed during the first week.", "By the end of Week 1, many people begin noticing: feeling sleepy earlier at night, falling asleep faster, and more consistent sleep patterns"], "highlight": "By the end of Week 1, many people begin noticing: feeling sleepy earlier at night, falling asleep faster, and more consistent sleep patterns"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, which controls the timing of melatonin release at night.", "proTip": "If possible, expose your eyes to sunlight before looking at your phone. This gives a stronger signal to your body clock."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and activates the relaxation response."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Morning Movement (Sleep Pressure Builder)", "duration": "10 min", "instructions": ["Perform 10 minutes of light physical movement.", "Choose one option or mix a few: brisk walking, mobility stretches, bodyweight squats (15 reps x 3), pushups (10 reps x 3)."], "whyThisWorks": "Movement early in the day helps build sleep pressure, making sleep easier at night."}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, delaying sleep."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the voice instructions.", "Allow the body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 7 that supports strengthening natural melatonin.", "audioStoragePath": "audio/sleep/7.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body experiences a natural drop in temperature, which signals the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet meadow under the stars.", "The night air is cool and peaceful.", "Everything around you is calm and still.", "Focus on this scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Dim Light Rule\"", "duration": "90 min setup", "steps": ["About 90 minutes before sleep, start reducing light exposure in your environment.", "Turn off bright ceiling lights", "Use warm or dim lighting", "Reduce screen brightness", "Avoid bright white lights"], "completionMessage": "Bright light in the evening blocks melatonin production, which delays sleep. Dim lighting signals the brain that nighttime has started, allowing melatonin to rise naturally."}, {"type": "close", "message": "Day 7 is complete.", "secondaryMessage": "Support the body''s natural melatonin cycle and strengthen the sleep routine developed during the first week."}]'::jsonb
)
