INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 8,
  'Strengthening Sleep Pressure', 'Day 8 - Strengthening Sleep Pressure', '', 22,
  '[{"type": "intro", "dayNumber": 8, "dayTitle": "Strengthening Sleep Pressure", "goal": "Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed.", "estimatedMinutes": 22}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed.", "By this stage many people begin noticing: stronger sleepiness at night, deeper sleep cycles, and more consistent sleep timing"], "highlight": "By this stage many people begin noticing: stronger sleepiness at night, deeper sleep cycles, and more consistent sleep timing"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping your body release melatonin naturally at night.", "proTip": "If possible, combine sunlight exposure with walking for 10 minutes."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This helps lower stress hormones and prepares the body for the day."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "15-20 min", "instructions": ["Starting today, increase movement to 15-20 minutes.", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "More physical activity during the day builds stronger sleep pressure, making it easier to fall asleep and enter deeper sleep cycles."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "15-20 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "10 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "15 reps x 4 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "10 reps x 4 sets"}, {"name": "Arm Circles", "instructions": ["Make slow controlled circles to wake up the shoulders."], "duration": "20 seconds x 3 sets"}, {"name": "Forward Bends Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "10 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours and disturb sleep quality."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 8 that supports strengthening sleep pressure.", "audioStoragePath": "audio/sleep/8.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly, which signals the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet forest clearing at night.", "A gentle breeze moves through the trees.", "The air is calm and peaceful.", "Focus on the scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "breathing_exercise", "title": "The \"4-7-8 Sleep Breathing\"", "pattern": {"inhaleSeconds": 4, "holdSeconds": 7, "exhaleSeconds": 8}, "cycles": 5, "instructions": "This breathing technique helps slow the nervous system and induce sleep. Inhale through your nose for 4 seconds Hold your breath for 7 seconds Slowly exhale through your mouth for 8 seconds Repeat 4-6 cycles. This breathing pattern: slows the heart rate relaxes the nervous system signals the brain to shift into sleep mode Many people feel noticeably calmer within a few minutes."}, {"type": "close", "message": "Day 8 is complete.", "secondaryMessage": "Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed."}]'::jsonb
)
