INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 9,
  'Deepening Sleep Pressure', 'Day 9 - Deepening Sleep Pressure', '', 22,
  '[{"type": "intro", "dayNumber": 9, "dayTitle": "Deepening Sleep Pressure", "goal": "Strengthen physical relaxation and sleep pressure, helping the body enter deeper sleep stages.", "estimatedMinutes": 22}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Strengthen physical relaxation and sleep pressure, helping the body enter deeper sleep stages.", "By Day 9 many people begin noticing: falling asleep faster, fewer night awakenings, and deeper relaxation before sleep"], "highlight": "By Day 9 many people begin noticing: falling asleep faster, fewer night awakenings, and deeper relaxation before sleep"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping regulate the timing of melatonin release at night.", "proTip": "Combine sunlight exposure with light walking for at least 10 minutes."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones and prepares the nervous system for the day."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "20 min", "instructions": ["Increase movement to about 20 minutes.", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "More physical activity increases adenosine buildup, which creates stronger sleep pressure and deeper sleep at night."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "20 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "10-12 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "15 reps x 4 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "12 reps x 4 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "20 reps x 3 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "10 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can stay in the body 6-8 hours, interfering with sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 9 that supports deepening sleep pressure.", "audioStoragePath": "audio/sleep/9.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature naturally drops, signaling the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet mountain cabin at night.", "Outside, gentle wind moves through the trees.", "Inside, everything feels warm and peaceful.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Progressive Muscle Relaxation\"", "duration": "5 min", "steps": ["This technique helps release hidden tension stored in the body, which often prevents deep sleep.", "While lying in bed:", "Tighten your feet muscles for 5 seconds.", "Release completely for 10 seconds.", "Then repeat the same pattern with:", "calves", "thighs", "stomach", "arms", "shoulders", "face", "Tighten each muscle group briefly, then release completely."], "completionMessage": "Many people carry physical tension without realizing it. Releasing this tension signals the brain that the body is safe and ready for sleep."}, {"type": "close", "message": "Day 9 is complete.", "secondaryMessage": "Strengthen physical relaxation and sleep pressure, helping the body enter deeper sleep stages."}]'::jsonb
)
