tion": "20-25 min", "instructions": ["Total movement time: 20-25 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher physical activity increases adenosine, the chemical responsible for sleep pressure. This helps the body feel naturally sleepy at night."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "20-25 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "12-15 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "20 reps x 4 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "12 reps x 4 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "25 reps x 3 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "10 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain in the body 6-8 hours, disturbing sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow the body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 10 that supports strengthening the sleep routine.", "audioStoragePath": "audio/sleep/10.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly, which signals the brain that it is time to sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet river under a starry sky.", "You hear gentle water flowing and the night is peaceful.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Mental Countdown\"", "duration": "2-5 min", "steps": ["This trick helps interrupt racing thoughts.", "While lying in bed, slowly count backwards from 100.", "## Example:", "100...", "99...", "98...", "97...", "Count slowly and calmly with your breathing.", "If your mind wanders, simply start again from 100."], "completionMessage": "Use this technique tonight and let the body settle at its own pace."}, {"type": "close", "message": "Day 10 is complete.", "secondaryMessage": "Strengthen the sleep routine and physical sleep pressure, while helping the mind disengage from thinking at night."}]'::jsonb
)
