  'Stabilizing Deep Sleep', 'Day 11 - Stabilizing Deep Sleep', '', 22,
  '[{"type": "intro", "dayNumber": 11, "dayTitle": "Stabilizing Deep Sleep", "goal": "Improve sleep stability and circulation, helping the body stay asleep longer and enter deeper sleep cycles.", "estimatedMinutes": 22}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Improve sleep stability and circulation, helping the body stay asleep longer and enter deeper sleep cycles.", "By Day 11 many people notice: fewer early morning awakenings, deeper relaxation at night, and more stable sleep patterns"], "highlight": "By Day 11 many people notice: fewer early morning awakenings, deeper relaxation at night, and more stable sleep patterns"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s internal clock, helping regulate the timing of melatonin release at night.", "proTip": "Combine sunlight exposure with 10 minutes of walking to strengthen your circadian rhythm."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "25 min", "instructions": ["Total movement time: 25 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher daytime activity builds stronger sleep pressure, helping the body stay asleep longer at night."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "25 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "15 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "20 reps x 4 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "15 reps x 4 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "30 reps x 3 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "10 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, affecting sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 11 that supports stabilizing deep sleep.", "audioStoragePath": "audio/sleep/11.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature naturally drops, signaling the brain to prepare for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet countryside field at night.", "The stars are bright above you and the air is peaceful.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Leg Elevation Trick\"", "duration": "5-10 min", "steps": ["This trick helps people who wake up too early in the morning or feel restless in bed.", "Before sleeping:", "Lie on your bed.", "Place your legs slightly elevated on a pillow.", "Keep them elevated for 5-10 minutes.", "Then return to your normal sleeping position."], "completionMessage": "Elevating the legs improves blood circulation and relaxation, which helps the body settle into deeper sleep. It also reduces physical restlessness that can disturb sleep during the night."}, {"type": "close", "message": "Day 11 is complete.", "secondaryMessage": "Improve sleep stability and circulation, helping the body stay asleep longer and enter deeper sleep cycles."}]'::jsonb
)
