VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 12,
  'Releasing Hidden Stress', 'Day 12 - Releasing Hidden Stress', '', 22,
  '[{"type": "intro", "dayNumber": 12, "dayTitle": "Releasing Hidden Stress", "goal": "Reduce mental stress before sleep, allowing the brain to transition more easily into sleep.", "estimatedMinutes": 22}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Reduce mental stress before sleep, allowing the brain to transition more easily into sleep.", "By Day 12 many people begin noticing: calmer thoughts at night, deeper emotional relaxation, and smoother transition into sleep"], "highlight": "By Day 12 many people begin noticing: calmer thoughts at night, deeper emotional relaxation, and smoother transition into sleep"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s internal clock, helping regulate melatonin production at night.", "proTip": "Try walking slowly during sunlight exposure to strengthen your circadian rhythm signal."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "25-30 min", "instructions": ["Total movement time: 25-30 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Stronger physical activity increases adenosine buildup, which increases sleep pressure and improves sleep depth."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "25-30 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "15 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "20 reps x 5 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "15 reps x 4 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "30 reps x 4 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "12 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, disturbing sleep quality."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow the body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 12 that supports releasing hidden stress.", "audioStoragePath": "audio/sleep/12.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly, which signals the brain that it is time to sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet waterfall in a peaceful forest.", "The sound of water is gentle and calming.", "Focus on the sound and the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "journal", "prompt": "Write down 3 things you are grateful for from today.", "helperText": "They can be small: a good conversation, a nice meal, or one peaceful moment.", "followUpPrompt": "Pause for a moment and mentally relive each one before bed."}, {"type": "close", "message": "Day 12 is complete.", "secondaryMessage": "Reduce mental stress before sleep, allowing the brain to transition more easily into sleep."}]'::jsonb
)
