VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 13,
  'Deep Body Relaxation', 'Day 13 - Deep Body Relaxation', '', 22,
  '[{"type": "intro", "dayNumber": 13, "dayTitle": "Deep Body Relaxation", "goal": "Encourage deep physical relaxation and nervous system calm, helping the body transition more easily into deep sleep stages.", "estimatedMinutes": 22}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Encourage deep physical relaxation and nervous system calm, helping the body transition more easily into deep sleep stages.", "By Day 13 many people begin noticing: deeper sleep cycles, less physical tension at night, and feeling more refreshed in the morning"], "highlight": "By Day 13 many people begin noticing: deeper sleep cycles, less physical tension at night, and feeling more refreshed in the morning"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s internal clock, helping regulate melatonin release at night.", "proTip": "Try combining sunlight exposure with slow walking to strengthen your circadian rhythm."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This helps reduce stress hormones and calm the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "30 min", "instructions": ["Total movement time: 30 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher daily activity increases sleep pressure and supports deeper sleep cycles."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "30 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "15-18 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "20 reps x 5 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "15 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "35 reps x 4 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "12 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, disturbing sleep."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow the body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 13 that supports deep body relaxation.", "audioStoragePath": "audio/sleep/13.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, your body temperature drops slightly, which signals the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet lake surrounded by mountains.", "The water is still and the night sky is full of stars.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Slow Blink Relaxation\"", "duration": "1-2 min", "steps": ["This trick helps relax the visual system and brain activity, which can keep people awake.", "While lying in bed:", "Close your eyes gently.", "Slowly open them halfway.", "Slowly close them again.", "Repeat this 8-10 times slowly."], "completionMessage": "Slow blinking relaxes the eye muscles and brain alertness system, helping the body transition into sleep mode. It mimics the natural blinking pattern that happens right before falling asleep."}, {"type": "close", "message": "Day 13 is complete.", "secondaryMessage": "Encourage deep physical relaxation and nervous system calm, helping the body transition more easily into deep sleep stages."}]'::jsonb
)
