VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 16,
  'Deep Sleep Conditioning', 'Day 16 - Deep Sleep Conditioning', '', 25,
  '[{"type": "intro", "dayNumber": 16, "dayTitle": "Deep Sleep Conditioning", "goal": "Train the brain to disconnect from mental stimulation, allowing the body to transition into sleep more smoothly.", "estimatedMinutes": 25}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Train the brain to disconnect from mental stimulation, allowing the body to transition into sleep more smoothly.", "By Day 16 many people notice: fewer racing thoughts, faster sleep onset, and deeper relaxation before sleep"], "highlight": "By Day 16 many people notice: fewer racing thoughts, faster sleep onset, and deeper relaxation before sleep"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, which controls the timing of melatonin release at night.", "proTip": "Combine sunlight exposure with light walking for the first 10 minutes."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "40 min", "instructions": ["Total movement time: 40 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher physical activity increases adenosine, the chemical responsible for sleep pressure. This helps the body enter deep restorative sleep more easily."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "40 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "20-22 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "25 reps x 5 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "20 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "50 reps x 4 sets"}, {"name": "Plank Hold", "instructions": ["Hold a straight line and keep breathing through the effort."], "duration": "40 seconds x 4 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "12 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can stay active in the body 6-8 hours, disturbing sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 16 that supports deep sleep conditioning.", "audioStoragePath": "audio/sleep/16.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature naturally drops, signaling the brain that it is time to sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet river under a peaceful night sky.", "The sound of water is gentle and relaxing.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Cognitive Defusion Trick\"", "duration": "1-2 min", "steps": ["Sometimes thoughts keep repeating in the mind at night.", "Instead of fighting the thought, label it and let it pass.", "When a thought appears, say silently:", "\"This is just a thought.\"", "Then let it pass and return to slow breathing.", "Do not analyze or continue the thought."], "completionMessage": "Trying to stop thoughts often makes them stronger. Labeling them as just thoughts removes their emotional power and allows the brain to relax."}, {"type": "close", "message": "Day 16 is complete.", "secondaryMessage": "Train the brain to disconnect from mental stimulation, allowing the body to transition into sleep more smoothly."}]'::jsonb
)
