INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 17,
  'Deep Nervous System Recovery', 'Day 17 - Deep Nervous System Recovery', '', 25,
  '[{"type": "intro", "dayNumber": 17, "dayTitle": "Deep Nervous System Recovery", "goal": "Encourage deep physical relaxation and nervous system calm, helping the body enter deeper restorative sleep cycles.", "estimatedMinutes": 25}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Encourage deep physical relaxation and nervous system calm, helping the body enter deeper restorative sleep cycles.", "By Day 17 many people notice: deeper sleep, fewer awakenings during the night, and waking up feeling more refreshed"], "highlight": "By Day 17 many people notice: deeper sleep, fewer awakenings during the night, and waking up feeling more refreshed"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, which controls melatonin release at night.", "proTip": "Try to combine sunlight with 10 minutes of walking."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and calms the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "40-45 min", "instructions": ["Total movement time: 40-45 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Increased physical movement builds stronger adenosine pressure, helping the body enter deep sleep stages faster."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "40-45 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "22-25 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "25 reps x 5 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "20 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "50 reps x 4 sets"}, {"name": "Plank Hold", "instructions": ["Hold a straight line and keep breathing through the effort."], "duration": "45 seconds x 4 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "12 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, interfering with sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 17 that supports deep nervous system recovery.", "audioStoragePath": "audio/sleep/17.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature naturally drops, signaling the brain that it is time to sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet forest clearing under the moonlight.", "The air is cool and peaceful.", "Everything around you is calm and silent.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Foot Massage Relaxation\"", "duration": "4-6 min", "steps": ["The feet contain many nerve endings connected to the nervous system.", "Relaxing them before bed can help the entire body relax.", "Before sleeping:", "Sit comfortably on the bed.", "Gently massage the bottom of each foot.", "Apply light pressure using your thumbs.", "Massage for 2-3 minutes per foot."], "completionMessage": "Foot massage stimulates relaxation pathways in the nervous system, reducing physical tension and helping the body transition into sleep."}, {"type": "close", "message": "Day 17 is complete.", "secondaryMessage": "Encourage deep physical relaxation and nervous system calm, helping the body enter deeper restorative sleep cycles."}]'::jsonb
)
