INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  '2b836834-5231-414f-af76-f0a460d9618f', 'sleep_disorder_reset', 18,
  'Deep Sleep Optimization', 'Day 18 - Deep Sleep Optimization', '', 25,
  '[{"type": "intro", "dayNumber": 18, "dayTitle": "Deep Sleep Optimization", "goal": "Deepen physical and neurological relaxation, preparing the body for stronger deep sleep cycles.", "estimatedMinutes": 25}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Deepen physical and neurological relaxation, preparing the body for stronger deep sleep cycles.", "By Day 18 many people notice: falling asleep more quickly, deeper sleep stages, and improved morning energy"], "highlight": "By Day 18 many people notice: falling asleep more quickly, deeper sleep stages, and improved morning energy"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping regulate melatonin release at night.", "proTip": "Combine sunlight exposure with 10 minutes of slow walking."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and relaxes the nervous system."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "45 min", "instructions": ["Total movement time: 45 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher activity increases adenosine accumulation, which strengthens sleep pressure and supports deeper sleep cycles."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "45 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "25 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "30 reps x 5 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "20 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "55 reps x 4 sets"}, {"name": "Plank Hold", "instructions": ["Hold a straight line and keep breathing through the effort."], "duration": "45 seconds x 5 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "12 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, interfering with sleep quality."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 18 that supports deep sleep optimization.", "audioStoragePath": "audio/sleep/18.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature drops slightly, signaling the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet lake under a moonlit sky.", "The water is still and the air is peaceful.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Eye Relaxation Method\"", "duration": "2-3 min", "steps": ["Eye tension can keep the brain in alert mode, especially after screen use.", "While lying in bed:", "Close your eyes gently.", "Imagine your eyeballs sinking deeper into the eye sockets.", "Let your eyes become very heavy and relaxed.", "Stay with this feeling for 2-3 minutes."], "completionMessage": "Relaxing the eye muscles signals the brain that alertness is no longer required, helping the nervous system transition into sleep mode."}, {"type": "close", "message": "Day 18 is complete.", "secondaryMessage": "Deepen physical and neurological relaxation, preparing the body for stronger deep sleep cycles."}]'::jsonb
)
