  '[{"type": "intro", "dayNumber": 20, "dayTitle": "Automatic Sleep Transition", "goal": "Allow the body to transition into sleep naturally and effortlessly, reinforcing the strong sleep habits built over the past 20 days.", "estimatedMinutes": 25}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Allow the body to transition into sleep naturally and effortlessly, reinforcing the strong sleep habits built over the past 20 days.", "By Day 20 many people notice: falling asleep almost automatically, deeper and longer sleep cycles, and improved morning energy"], "highlight": "By Day 20 many people notice: falling asleep almost automatically, deeper and longer sleep cycles, and improved morning energy"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight resets the brain''s circadian rhythm, helping regulate melatonin production at night.", "proTip": "Combine sunlight exposure with 10-12 minutes of walking."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This reduces stress hormones and activates the relaxation response."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Increased Morning Movement (Sleep Pressure Builder)", "duration": "50 min", "instructions": ["Total movement time: 50 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Higher physical activity strengthens sleep pressure, helping the body enter deeper sleep cycles faster."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "50 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "28-30 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "30 reps x 6 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "22 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "60 reps x 5 sets"}, {"name": "Plank Hold", "instructions": ["Hold a straight line and keep breathing through the effort."], "duration": "55 seconds x 5 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "15 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Follow this rule strictly:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Caffeine can remain active in the body 6-8 hours, disturbing sleep cycles."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 20 that supports automatic sleep transition.", "audioStoragePath": "audio/sleep/20.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature drops slightly, signaling the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying in a quiet valley surrounded by mountains at night.", "The air is cool and peaceful.", "Everything around you is calm and still.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Breath Counting Drift\"", "duration": "2-5 min", "steps": ["This technique helps the brain drift naturally into sleep.", "While lying in bed:", "Take slow nasal breaths.", "Count each exhale.", "## Example:", "Exhale 1", "Exhale 2", "Exhale 3", "Continue until 10, then start again.", "Keep breathing slow and calm."], "completionMessage": "Counting breaths keeps the brain lightly focused, preventing racing thoughts while allowing the body to drift into sleep. It creates a gentle mental rhythm that supports sleep onset."}, {"type": "close", "message": "Day 20 is complete.", "secondaryMessage": "Allow the body to transition into sleep naturally and effortlessly, reinforcing the strong sleep habits built over the past 20 days."}]'::jsonb
)
