  '[{"type": "intro", "dayNumber": 21, "dayTitle": "Long-Term Sleep Stability", "goal": "Lock in the sleep habits and routines developed during the past 21 days so they continue working long term.", "estimatedMinutes": 25}, {"type": "lesson", "title": "What to notice today", "paragraphs": ["Lock in the sleep habits and routines developed during the past 21 days so they continue working long term.", "By the end of the program many people notice: consistent sleep timing, deeper sleep cycles, easier sleep onset, and improved morning energy"], "highlight": "By the end of the program many people notice: consistent sleep timing, deeper sleep cycles, easier sleep onset, and improved morning energy"}, {"type": "action_step", "stepNumber": 1, "title": "Morning Sunlight Exposure (10-20 Minutes)", "duration": "10-20 min", "instructions": ["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.", "Step outside your home, balcony, or street.", "Do not wear sunglasses.", "Face the direction of the sky (not directly at the sun).", "Stay outside for 10-20 minutes."], "whyThisWorks": "Morning sunlight keeps your circadian rhythm stable, helping the body release melatonin at the correct time every night.", "proTip": "Combine sunlight exposure with 10-15 minutes of walking."}, {"type": "action_step", "stepNumber": 2, "title": "Hydration + Nervous System Activation", "duration": "2-3 min", "instructions": ["Immediately after sunlight, drink 500-700 ml of water.", "Then complete 10 cycles of the physiological sigh before moving on."], "whyThisWorks": "This lowers stress hormones and prepares the nervous system for the day."}, {"type": "breathing_exercise", "title": "Physiological Sigh", "pattern": {"inhaleSeconds": 3, "exhaleSeconds": 6}, "cycles": 10, "instructions": "Inhale through the nose, take a short second sip of air at the top, then slowly exhale through the mouth."}, {"type": "action_step", "stepNumber": 3, "title": "Final Movement Routine (Sleep Pressure Builder)", "duration": "50-55 min", "instructions": ["Total movement time: 50-55 minutes", "Use the routine below to build sleep pressure early in the day."], "whyThisWorks": "Strong daytime movement builds powerful sleep pressure, allowing the body to enter deep restorative sleep cycles."}, {"type": "exercise_routine", "title": "Morning movement routine", "totalDuration": "50-55 min", "exercises": [{"name": "Brisk Walking", "instructions": ["Walk at a steady, relaxed pace in the morning light."], "duration": "30 minutes continuous walking."}, {"name": "Bodyweight Squats", "instructions": ["Lower with control and stand tall through each rep."], "reps": "35 reps x 6 sets"}, {"name": "Pushups", "instructions": ["Keep your body long and your core engaged."], "reps": "25 reps x 5 sets"}, {"name": "Jumping Jacks", "instructions": ["Keep the movement rhythmic and light."], "reps": "65 reps x 5 sets"}, {"name": "Plank Hold", "instructions": ["Hold a straight line and keep breathing through the effort."], "duration": "60 seconds x 5 sets"}, {"name": "Standing Forward Stretch", "instructions": ["Move slowly and breathe through each stretch."], "reps": "15 slow repetitions"}]}, {"type": "action_step", "stepNumber": 4, "title": "Caffeine Control Rule", "instructions": ["Continue following this rule:", "No caffeine after 2 PM", "This includes: coffee, tea, energy drinks, pre-workout drinks."], "whyThisWorks": "Reducing late caffeine protects sleep quality and sleep depth."}, {"type": "action_step", "stepNumber": 5, "title": "Evening Nervous System Downshift", "duration": "10-20 minutes.", "instructions": ["About 60 minutes before bed, listen to your guided sleep meditation audio.", "Lie comfortably in bed.", "Play the meditation audio at low volume.", "Close your eyes and follow the instructions.", "Allow your body to relax naturally."]}, {"type": "audio", "title": "Guided Sleep Meditation", "description": "A gentle bedtime audio for Day 21 that supports long-term sleep stability.", "audioStoragePath": "audio/sleep/21.mp3", "durationSeconds": 900}, {"type": "action_step", "stepNumber": 6, "title": "Body Temperature Sleep Trick", "instructions": ["Take a warm shower 60-90 minutes before sleep."], "whyThisWorks": "After the shower, the body temperature drops slightly, signaling the brain that it is time for sleep."}, {"type": "action_step", "stepNumber": 7, "title": "The Military Sleep Method (Fast Sleep Technique)", "duration": "3-5 min", "instructions": ["Relax your forehead", "Relax jaw and tongue", "Drop shoulders completely", "Slowly breathe out"]}, {"type": "mindfulness_exercise", "title": "Military sleep imagery", "duration": "3-5 min", "steps": ["You are lying beside a quiet lake under a clear night sky.", "The water is still and the night air is peaceful.", "Focus on the calm scene while breathing slowly.", "If thoughts appear, gently return to the scene and keep breathing slowly."], "completionMessage": "Let the scene stay soft and steady until sleep takes over."}, {"type": "mindfulness_exercise", "title": "The \"Sleep Anchor\"", "duration": "1 min", "steps": ["This technique helps the brain associate one consistent cue with sleep.", "Choose one simple action you will repeat every night before sleep, such as:", "turning on your meditation audio", "dimming the lights", "taking 5 slow breaths", "Repeat the same action every night before sleeping."], "completionMessage": "The brain begins to associate that action with sleep time. Over time, the brain will start triggering sleep almost automatically when the cue happens."}, {"type": "close", "message": "Day 21 is complete.", "secondaryMessage": "Lock in the sleep habits and routines developed during the past 21 days so they continue working long term."}]'::jsonb
